import { createRequire } from "node:module";

import { Command } from "commander";
import { render, useApp } from "ink";
import { HelloWorld } from "@maestro/tui";
import { createElement, useEffect } from "react";

import { resolveCliMode } from "./mode.js";

const CLI_PACKAGE_NAME = "@maestro/cli";
const require = createRequire(import.meta.url);
const packageJson = require("../package.json") as { version: string };

function HelloWorldApp(props: { autoExit: boolean; version: string }) {
  const { autoExit, version } = props;
  const { exit } = useApp();

  useEffect(() => {
    if (!autoExit) {
      return;
    }

    const timer = setTimeout(() => {
      exit();
    }, 0);

    return () => {
      clearTimeout(timer);
    };
  }, [autoExit, exit]);

  return createElement(HelloWorld, { version });
}

function createProgram(version: string) {
  return new Command()
    .name("maestro")
    .description("Multi-agent coding orchestrator")
    .version(version);
}

export function runCli(args: string[]) {
  const version = packageJson.version;
  const mode = resolveCliMode(args);

  if (mode !== "app") {
    createProgram(version).parse(["node", "maestro", ...args]);
    return;
  }

  render(
    createElement(HelloWorldApp, {
      autoExit: !process.stdout.isTTY,
      version,
    }),
  );
}

runCli(process.argv.slice(2));

export { CLI_PACKAGE_NAME };
